      extracted: {},

      analysis: {
        classification: null,
        risk_level: null,
        compliance_score: null,
        priority_score: null
      },

      workflow: {
        stage: "initialized",
        status: "ready_for_analysis"
      }
    }
  }
];

const raw =
  $json.output?.[0]?.content?.[0]?.text ||
  $json.output?.[0]?.text ||
  $json.text ||
  "";

function extractJsonBlock(str) {
  const first = str.indexOf("{");
  const last = str.lastIndexOf("}");
  if (first === -1 || last === -1 || last <= first) return null;
  return str.slice(first, last + 1);
}

const jsonBlock = extractJsonBlock(raw);

if (!jsonBlock) {
  return [
    {
      json: {
        ...$json,
        parse_error: true,
        parse_error_message: "No JSON object found in classifier output",
        raw_classifier_output: raw
      }
    }
  ];
}

let parsed;
try {
  parsed = JSON.parse(jsonBlock);
} catch (e) {
  return [
    {
      json: {
        ...$json,
        parse_error: true,
        parse_error_message: e.message,
        raw_classifier_output: raw,
        extracted_json_block: jsonBlock
      }
    }
  ];
}

return [
  {
    json: {
      ...$json,
      analysis: {
        ...($json.analysis || {}),
        classification: parsed.classification || null
      },
      classifier_summary: parsed.summary || "",
      classifier_confidence: parsed.confidence ?? null,
